// Reset state\n    });\n    CsprClickCallbacks.onTransactionStatusUpdate((status: TransactionStatus, data: TransactionResult) => {\n        console.log(\'Transaction status update handler:\', status, data);\n        onTransactionStatusUpdate(status, data);\n    });\n}\n\n// 4. Start the initialization process\nrun().catch(err => console.error("Failed to initialize:", err));\n'})}),"\n",(0,r.jsx)(e.p,{children:"There a few key steps to note in the above code:"}),"\n",(0,r.jsxs)(e.ol,{children:["\n",(0,r.jsxs)(e.li,{children:[(0,r.jsx)(e.strong,{children:"WASM Initialization"}),": The ",(0,r.jsx)(e.code,{children:"init()"})," function is called to initialize the WASM module."]}),"\n",(0,r.jsxs)(e.li,{children:[(0,r.jsx)(e.strong,{children:"Client Setup"}),": An instance of ",(0,r.jsx)(e.code,{children:"OdraWasmClient"})," is created to connect to the Casper blockchain, and a ",(0,r.jsx)(e.code,{children:"CounterWasmClient"})," is instantiated to interact with the ",(0,r.jsx)(e.code,{children:"Counter"})," contract."]}),"\n",(0,r.jsxs)(e.li,{children:[(0,r.jsx)(e.strong,{children:"Cspr.Click Callbacks"}),": Custom callbacks are set up to handle events such as signing in, switching accounts, signing out, and transaction status updates."]}),"\n"]}),"\n",(0,r.jsx)(e.p,{children:"We will take a closer look at these components in the sections below."}),"\n",(0,r.jsx)(e.h2,{id:"odra-wasm-client",children:"Odra Wasm Client"}),"\n",(0,r.jsxs)(e.p,{children:[(0,r.jsx)(e.code,{children:"OdraWasmClient"})," is a key component of the Odra Wasm client library that facilitates interaction with contracts deployed on the Casper blockchain\nand seamslessly integrates with CsprClick."]}),"\n",(0,r.jsxs)(e.p,{children:["It abstracts away the complexities of interacting with the blockchain, allowing you to focus on building your application logic. You don't need to worry\nabout low-level details such as constructing transactions or handling signatures; the ",(0,r.jsx)(e.code,{children:"O